// Basit hash table implementasyonu
class HashTable {
    constructor(size = 50) {
        this.buckets = new Array(size);
    }

    hash(key) {
        let hash = 0;
        for (let char of key) {
            hash += char.charCodeAt(0);
        }
        return hash % this.buckets.length;
    }

    set(key, value) {
        const index = this.hash(key);
        this.buckets[index] = value;
    }

    get(key) {
        const index = this.hash(key);
        return this.buckets[index];
    }
}

