subject.subscribe(observer2);

subject.notify('Hello!');  // Her iki observer da bildirim alır

subject.unsubscribe(observer1);
subject.notify('Goodbye!');  // Sadece observer2 alır

// Revealing Module Pattern
const Calculator = (() => {
    // Private
    let result = 0;

    function log(message) {
        console.log(`[Calculator] ${message}`);
    }

    // Public
    function add(x) {
        result += x;
        log(`Added ${x}, result: ${result}`);
        return this;
    }

    function subtract(x) {
        result -= x;
        log(`Subtracted ${x}, result: ${result}`);
        return this;
    }

    function getResult() {
        return result;
    }

    function reset() {
        result = 0;
        log('Reset');
    }

    // Public API
    return {
        add,
        subtract,
        getResult,
        reset
    };
})();

// Kullanım
